/**
 * Quick esbuild script for building pkg/storaged during development.
 * Replicates the cockpit build.js plugin pattern for cockpit externals.
 *
 * IMPORTANT: This only builds storaged.js. The system-installed storaged.css
 * (from cockpit-storaged package) must be preserved — do NOT deploy the
 * storaged.css generated by this build. SCSS files are stubbed to empty
 * to prevent broken CSS output.
 *
 * Usage: NODE_PATH=node_modules node build-storaged.cjs
 * Deploy: gzip -kf pkg/storaged/storaged.js && scp ... (JS only!)
 */
const esbuild = require('esbuild');

const cockpitResolvePlugin = {
    name: 'cockpit-resolve',
    setup(build) {
        // cockpit → global cockpit variable (provided by framework)
        build.onResolve({ filter: /^cockpit$/ }, args => {
            return { path: 'cockpit', namespace: 'global-shim' };
        });
        build.onLoad({ filter: /.*/, namespace: 'global-shim' }, args => {
            return { contents: `module.exports = ${args.path}` };
        });

        // cockpit-dark-theme, polyfills → empty modules (framework provides them)
        build.onResolve({ filter: /^(cockpit-dark-theme|polyfills)$/ }, args => {
            return { path: args.path, namespace: 'empty-shim' };
        });
        build.onLoad({ filter: /.*/, namespace: 'empty-shim' }, args => {
            return { contents: '' };
        });

        // SCSS files → empty (system CSS handles PatternFly; topology CSS is injected at runtime)
        build.onResolve({ filter: /\.scss$/ }, args => {
            return { path: args.path, namespace: 'empty-scss' };
        });
        build.onLoad({ filter: /.*/, namespace: 'empty-scss' }, args => {
            return { contents: '', loader: 'css' };
        });
    },
};

esbuild.build({
    entryPoints: ['pkg/storaged/storaged.jsx'],
    bundle: true,
    outdir: 'pkg/storaged',
    outbase: 'pkg/storaged',
    loader: {
        '.jsx': 'jsx',
        '.js': 'jsx',
        '.ts': 'ts',
        '.tsx': 'tsx',
        '.py': 'text',
        '.sh': 'text',
    },
    external: ['*.woff', '*.woff2', '*.jpg', '*.svg'],
    nodePaths: ['pkg/lib'],
    target: ['es2021'],
    plugins: [cockpitResolvePlugin],
    define: { 'process.env.NODE_ENV': '"production"' },
    minify: false,
}).then(() => console.log('Build OK — deploy ONLY storaged.js.gz, NOT storaged.css.gz')).catch(e => { console.error(e); process.exit(1); });
